import pytest
import requests

def test_search_by_name_returns_only_assigned_patients(
    clinician_auth_fixture, assigned_patient_ids, base_url
):
    token = clinician_auth_fixture["token"]
    headers = {"Authorization": f"Bearer {token}"}
    resp = requests.get(
        f"{base_url}/Patient",
        params={"search": "name=Smith"},
        headers=headers,
        timeout=10,
    )
    assert resp.status_code == 200
    bundle = resp.json()
    assert bundle.get("resourceType") == "Bundle"
    returned_ids = {
        e["resource"]["id"]
        for e in bundle.get("entry", [])
    }
    assert returned_ids, "Bundle must contain at least one entry"
    for pid in returned_ids:
        assert pid in assigned_patient_ids, (
            f"Patient {pid} not in clinician care list"
        )

import pytest
import requests

def test_single_char_name_search_is_accepted(
    clinician_auth_fixture, assigned_patient_ids, base_url
):
    token = clinician_auth_fixture["token"]
    headers = {"Authorization": f"Bearer {token}"}
    resp = requests.get(
        f"{base_url}/Patient",
        params={"search": "name=S"},
        headers=headers,
        timeout=10,
    )
    assert resp.status_code == 200, (
        f"Single-char query must not be rejected; got {resp.status_code}"
    )
    bundle = resp.json()
    assert bundle.get("resourceType") == "Bundle"
    for entry in bundle.get("entry", []):
        pid = entry["resource"]["id"]
        assert pid in assigned_patient_ids, (
            f"Patient {pid} outside care list returned"
        )
